import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { OpenChatAgentCreateForm, OpenChatFileUploadSessionForm, OpenChatSearchForm, OpenChatSettingsUpdateForm, OpenChatUploadCompleteForm, PlusApiResultAgentVO, PlusApiResultCursorFeedVO, PlusApiResultFileUploadChunkVO, PlusApiResultFileUploadSessionVO, PlusApiResultFileVO, PlusApiResultListDeviceVO, PlusApiResultPageAgentVO, PlusApiResultPageAppVO, PlusApiResultPageMomentVO, PlusApiResultPageNotificationVO, PlusApiResultPageSearchItemVO, PlusApiResultPageSkillVO, PlusApiResultPageToolVO, PlusApiResultPageVideoVO, PlusApiResultPageWalletTransactionVO, PlusApiResultSettingsVO, PlusApiResultWalletSummaryVO } from '../types';


export class OpenchatApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** List agents */
  async getList(params?: QueryParams): Promise<PlusApiResultPageAgentVO> {
    return this.client.get<PlusApiResultPageAgentVO>(appApiPath(`/openchat/agents`), params);
  }

/** Create agent */
  async create(body: OpenChatAgentCreateForm): Promise<PlusApiResultAgentVO> {
    return this.client.post<PlusApiResultAgentVO>(appApiPath(`/openchat/agents`), body);
  }

/** Get agent detail */
  async detail(agentId: string | number): Promise<PlusApiResultAgentVO> {
    return this.client.get<PlusApiResultAgentVO>(appApiPath(`/openchat/agents/${agentId}`));
  }

/** Wallet summary */
  async summary(): Promise<PlusApiResultWalletSummaryVO> {
    return this.client.get<PlusApiResultWalletSummaryVO>(appApiPath(`/openchat/wallet/summary`));
  }

/** Wallet transactions */
  async transactions(params?: QueryParams): Promise<PlusApiResultPageWalletTransactionVO> {
    return this.client.get<PlusApiResultPageWalletTransactionVO>(appApiPath(`/openchat/wallet/transactions`), params);
  }

/** List short videos */
  async getListVideos(params?: QueryParams): Promise<PlusApiResultPageVideoVO> {
    return this.client.get<PlusApiResultPageVideoVO>(appApiPath(`/openchat/videos`), params);
  }

/** Discover feed */
  async feed(params?: QueryParams): Promise<PlusApiResultCursorFeedVO> {
    return this.client.get<PlusApiResultCursorFeedVO>(appApiPath(`/openchat/discover/feed`), params);
  }

/** Notification page query */
  async page(params?: QueryParams): Promise<PlusApiResultPageNotificationVO> {
    return this.client.get<PlusApiResultPageNotificationVO>(appApiPath(`/openchat/notifications/page`), params);
  }

/** Unified search query */
  async query(body: OpenChatSearchForm): Promise<PlusApiResultPageSearchItemVO> {
    return this.client.post<PlusApiResultPageSearchItemVO>(appApiPath(`/openchat/search/query`), body);
  }

/** Get user setting profile */
  async get(): Promise<PlusApiResultSettingsVO> {
    return this.client.get<PlusApiResultSettingsVO>(appApiPath(`/openchat/settings`));
  }

/** Update user settings */
  async update(body: OpenChatSettingsUpdateForm): Promise<PlusApiResultSettingsVO> {
    return this.client.put<PlusApiResultSettingsVO>(appApiPath(`/openchat/settings`), body);
  }

/** Skill market list */
  async getMarket(params?: QueryParams): Promise<PlusApiResultPageSkillVO> {
    return this.client.get<PlusApiResultPageSkillVO>(appApiPath(`/openchat/skills/market`), params);
  }

/** Tool market list */
  async getMarketTools(params?: QueryParams): Promise<PlusApiResultPageToolVO> {
    return this.client.get<PlusApiResultPageToolVO>(appApiPath(`/openchat/tools/market`), params);
  }

/** Moments list */
  async moments(params?: QueryParams): Promise<PlusApiResultPageMomentVO> {
    return this.client.get<PlusApiResultPageMomentVO>(appApiPath(`/openchat/social/moments`), params);
  }

/** Device list */
  async getListDevices(): Promise<PlusApiResultListDeviceVO> {
    return this.client.get<PlusApiResultListDeviceVO>(appApiPath(`/openchat/devices`));
  }

/** App store app list */
  async apps(params?: QueryParams): Promise<PlusApiResultPageAppVO> {
    return this.client.get<PlusApiResultPageAppVO>(appApiPath(`/openchat/appstore/apps`), params);
  }

/** Create file upload session */
  async createUploadSession(body: OpenChatFileUploadSessionForm): Promise<PlusApiResultFileUploadSessionVO> {
    return this.client.post<PlusApiResultFileUploadSessionVO>(appApiPath(`/openchat/files/upload/session`), body);
  }

/** Upload file chunk */
  async uploadChunk(body: FormData): Promise<PlusApiResultFileUploadChunkVO> {
    return this.client.post<PlusApiResultFileUploadChunkVO>(appApiPath(`/openchat/files/upload/chunk`), body);
  }

/** Complete file upload */
  async completeUpload(body: OpenChatUploadCompleteForm): Promise<PlusApiResultFileVO> {
    return this.client.post<PlusApiResultFileVO>(appApiPath(`/openchat/files/upload/complete`), body);
  }
}

export function createOpenchatApi(client: HttpClient): OpenchatApi {
  return new OpenchatApi(client);
}
