import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { AppCreateForm, AppPublishPlanUpdateForm, AppPublishPreviewForm, AppReleaseNotesUpdateForm, AppUpdateCheckForm, AppUpdateForm, PlusApiResultAppDetailVO, PlusApiResultAppPublishPlanVO, PlusApiResultAppPublishReadinessVO, PlusApiResultAppReleaseNotesVO, PlusApiResultAppStatisticsVO, PlusApiResultAppUpdateCheckVO, PlusApiResultAppVO, PlusApiResultListAppStoreCategoryVO, PlusApiResultPageAppVO, PlusApiResultVoid } from '../types';


export class AppApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** Get app detail */
  async retrieve(appId: string | number): Promise<PlusApiResultAppDetailVO> {
    return this.client.get<PlusApiResultAppDetailVO>(appApiPath(`/app/manage/${appId}`));
  }

/** Update app */
  async updateApp(appId: string | number, body: AppUpdateForm): Promise<PlusApiResultAppVO> {
    return this.client.put<PlusApiResultAppVO>(appApiPath(`/app/manage/${appId}`), body);
  }

/** Delete app */
  async deleteApp(appId: string | number): Promise<PlusApiResultVoid> {
    return this.client.delete<PlusApiResultVoid>(appApiPath(`/app/manage/${appId}`));
  }

/** Get app release notes */
  async getReleaseNotes(appId: string | number): Promise<PlusApiResultAppReleaseNotesVO> {
    return this.client.get<PlusApiResultAppReleaseNotesVO>(appApiPath(`/app/manage/${appId}/release-notes`));
  }

/** Update app release notes */
  async updateReleaseNotes(appId: string | number, body: AppReleaseNotesUpdateForm): Promise<PlusApiResultAppReleaseNotesVO> {
    return this.client.put<PlusApiResultAppReleaseNotesVO>(appApiPath(`/app/manage/${appId}/release-notes`), body);
  }

/** Get publish plan */
  async getPublishPlan(appId: string | number): Promise<PlusApiResultAppPublishPlanVO> {
    return this.client.get<PlusApiResultAppPublishPlanVO>(appApiPath(`/app/manage/${appId}/publish/plan`));
  }

/** Update publish plan */
  async updatePublishPlan(appId: string | number, body: AppPublishPlanUpdateForm): Promise<PlusApiResultAppPublishPlanVO> {
    return this.client.put<PlusApiResultAppPublishPlanVO>(appApiPath(`/app/manage/${appId}/publish/plan`), body);
  }

/** Check update */
  async checkAppUpdate(body: AppUpdateCheckForm): Promise<PlusApiResultAppUpdateCheckVO> {
    return this.client.post<PlusApiResultAppUpdateCheckVO>(appApiPath(`/app/update/check`), body);
  }

/** Create app */
  async createApp(body: AppCreateForm): Promise<PlusApiResultAppVO> {
    return this.client.post<PlusApiResultAppVO>(appApiPath(`/app/manage`), body);
  }

/** Preview publish result */
  async previewPublish(appId: string | number, body: AppPublishPreviewForm): Promise<PlusApiResultAppUpdateCheckVO> {
    return this.client.post<PlusApiResultAppUpdateCheckVO>(appApiPath(`/app/manage/${appId}/publish/preview`), body);
  }

/** Deactivate app */
  async deactivate(appId: string | number): Promise<PlusApiResultVoid> {
    return this.client.post<PlusApiResultVoid>(appApiPath(`/app/manage/${appId}/deactivate`));
  }

/** Activate app */
  async activate(appId: string | number): Promise<PlusApiResultVoid> {
    return this.client.post<PlusApiResultVoid>(appApiPath(`/app/manage/${appId}/activate`));
  }

/** Check publish readiness */
  async checkPublishReadiness(appId: string | number): Promise<PlusApiResultAppPublishReadinessVO> {
    return this.client.get<PlusApiResultAppPublishReadinessVO>(appApiPath(`/app/manage/${appId}/publish/readiness`));
  }

/** Get app statistics */
  async getAppStatistics(): Promise<PlusApiResultAppStatisticsVO> {
    return this.client.get<PlusApiResultAppStatisticsVO>(appApiPath(`/app/manage/statistics`));
  }

/** Search apps */
  async searchApps(params?: QueryParams): Promise<PlusApiResultPageAppVO> {
    return this.client.get<PlusApiResultPageAppVO>(appApiPath(`/app/manage/search`), params);
  }

/** List project apps */
  async getProjectApps(projectId: string | number, params?: QueryParams): Promise<PlusApiResultPageAppVO> {
    return this.client.get<PlusApiResultPageAppVO>(appApiPath(`/app/manage/project/${projectId}`), params);
  }

/** List my apps */
  async getMyApps(params?: QueryParams): Promise<PlusApiResultPageAppVO> {
    return this.client.get<PlusApiResultPageAppVO>(appApiPath(`/app/manage/my`), params);
  }

/** List app store apps */
  async listStoreApps(params?: QueryParams): Promise<PlusApiResultPageAppVO> {
    return this.client.get<PlusApiResultPageAppVO>(appApiPath(`/app/store`), params);
  }

/** List app store categories */
  async listStoreCategories(): Promise<PlusApiResultListAppStoreCategoryVO> {
    return this.client.get<PlusApiResultListAppStoreCategoryVO>(appApiPath(`/app/store/categories`));
  }

/** Get public app store detail */
  async retrieveStore(appId: string | number): Promise<PlusApiResultAppDetailVO> {
    return this.client.get<PlusApiResultAppDetailVO>(appApiPath(`/app/store/${appId}`));
  }
}

export function createAppApi(client: HttpClient): AppApi {
  return new AppApi(client);
}
